export const meta = { name: 'judge_claims', description: 'Judge three simple claims and synthesize verdicts', phases: [{ title: 'Scan' }, { title: 'Final' }] };

const itemSchema = {
  type: 'object',
  additionalProperties: false,
  required: ['claim', 'verdict', 'reason'],
  properties: {
    claim: { type: 'string' },
    verdict: { type: 'string', enum: ['TRUE', 'FALSE'] },
    reason: { type: 'string' }
  }
};

const finalSchema = {
  type: 'object',
  additionalProperties: false,
  required: ['claims', 'overall'],
  properties: {
    claims: { type: 'array', minItems: 3, maxItems: 3, items: itemSchema },
    overall: { type: 'string' }
  }
};

phase('Scan');
const inputs = [
  { label: 'claim A', text: 'A) The Earth orbits the Sun.' },
  { label: 'claim B', text: 'B) Water boils at 10 degrees Celsius at sea level.' },
  { label: 'claim C', text: 'C) 7 is a prime number.' }
];
const claims = await parallel(inputs.map(item => () => agent(`Judge: ${item.text}`, { label: item.label, tier: 'small', schema: itemSchema })));

phase('Final');
return await agent(`Aggregate: ${JSON.stringify(claims)}`, { label: 'final synthesis', tier: 'small', schema: finalSchema });

